func (o *ResultEntry) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "CarClass":
		rel, ok := retrieved.(*CarClass)
		if !ok {
			return fmt.Errorf("resultEntry cannot load %T as %q", retrieved, name)
		}

		o.R.CarClass = rel

		if rel != nil {
			rel.R.ResultEntries = ResultEntrySlice{o}
		}
		return nil
	case "CarModel":
		rel, ok := retrieved.(*CarModel)
		if !ok {
			return fmt.Errorf("resultEntry cannot load %T as %q", retrieved, name)
		}

		o.R.CarModel = rel

		if rel != nil {
			rel.R.ResultEntries = ResultEntrySlice{o}
		}
		return nil
	case "Driver":
		rel, ok := retrieved.(*Driver)
		if !ok {
			return fmt.Errorf("resultEntry cannot load %T as %q", retrieved, name)
		}

		o.R.Driver = rel

		if rel != nil {
			rel.R.ResultEntries = ResultEntrySlice{o}
		}
		return nil
	case "RaceGrid":
		rel, ok := retrieved.(*RaceGrid)
		if !ok {
			return fmt.Errorf("resultEntry cannot load %T as %q", retrieved, name)
		}

		o.R.RaceGrid = rel

		if rel != nil {
			rel.R.ResultEntries = ResultEntrySlice{o}
		}
		return nil
	case "Team":
		rel, ok := retrieved.(*Team)
		if !ok {
			return fmt.Errorf("resultEntry cannot load %T as %q", retrieved, name)
		}

		o.R.Team = rel

		if rel != nil {
			rel.R.ResultEntries = ResultEntrySlice{o}
		}
		return nil
	default:
		return fmt.Errorf("resultEntry has no relationship %q", name)
	}
}

